// // This module implements an asynchronous up-counter with synchronous reset.
module top_module
(
    input clk,
    input sreset,
    output reg [5:0] count
);always @(posedge clk)
        if (sreset) begin
            count <= 6'b111111;
        end else begin
            count <= count - 1;
        end
endmodule
